object ApiLogger {

    private const val TAG = "ApiLogger"

    fun logRequest(
        method: String,
        url: String,
        headers: Map<String, String> = emptyMap(),
        body: String? = null,
        requestId: String = ""
    ) {
        val sanitizedHeaders = LogSanitizer.sanitizeHeaders(headers)
        val sanitizedBody = LogSanitizer.sanitizeBody(body)
        val sanitizedUrl = LogSanitizer.sanitizeText(url)

        val metadata = mutableMapOf(
            "method" to method,
            "url" to sanitizedUrl,
            "headers" to sanitizedHeaders.toString()
        )
        if (requestId.isNotEmpty()) {
            metadata["request_id"] = requestId
        }
        if (body != null) {
            metadata["body"] = sanitizedBody
            metadata["body_size"] = "${body.length} bytes"
        }

        val entry = LogEntry(
            level = LogLevel.INFO,
            tag = TAG,
            category = LogCategory.API,
            message = "API Request: $method $sanitizedUrl",
            metadata = metadata
        )
        AppLogger.log(entry)
    }

    fun logResponse(
        method: String,
        url: String,
        statusCode: Int,
        headers: Map<String, String> = emptyMap(),
        body: String? = null,
        durationMs: Long = 0,
        requestId: String = ""
    ) {
        val sanitizedHeaders = LogSanitizer.sanitizeHeaders(headers)
        val sanitizedBody = LogSanitizer.sanitizeBody(body)
        val sanitizedUrl = LogSanitizer.sanitizeText(url)
        val level = when {
            statusCode in 200..299 -> LogLevel.INFO
            statusCode in 300..399 -> LogLevel.INFO
            statusCode in 400..499 -> LogLevel.WARN
            else -> LogLevel.ERROR
        }

        val metadata = mutableMapOf(
            "method" to method,
            "url" to sanitizedUrl,
            "status_code" to statusCode.toString(),
            "duration_ms" to durationMs.toString(),
            "response_headers" to sanitizedHeaders.toString()
        )
        if (requestId.isNotEmpty()) {
            metadata["request_id"] = requestId
        }
        if (body != null) {
            metadata["response_body"] = sanitizedBody
            metadata["response_size"] = "${body.length} bytes"
        }

        val entry = LogEntry(
            level = level,
            tag = TAG,
            category = LogCategory.API,
            message = "API Response: $method $sanitizedUrl -> $statusCode (${durationMs}ms)",
            metadata = metadata
        )
        AppLogger.log(entry)
    }

    fun logError(
        method: String,
        url: String,
        throwable: Throwable,
        durationMs: Long = 0,
        requestId: String = ""
    ) {
        val sanitizedUrl = LogSanitizer.sanitizeText(url)
        val metadata = mutableMapOf(
            "method" to method,
            "url" to sanitizedUrl,
            "duration_ms" to durationMs.toString(),
            "exception" to (throwable::class.simpleName ?: "Unknown"),
            "error_message" to (throwable.message ?: "No message"),
            "stack_trace" to LogSanitizer.sanitizeStackTrace(throwable)
        )
        if (requestId.isNotEmpty()) {
            metadata["request_id"] = requestId
        }

        val entry = LogEntry(
            level = LogLevel.ERROR,
            tag = TAG,
            category = LogCategory.API,
            message = "API Error: $method $sanitizedUrl - ${throwable::class.simpleName}: ${throwable.message}",
            metadata = metadata
        )
        AppLogger.log(entry)
    }

    fun logTimeout(method: String, url: String, timeoutMs: Long, requestId: String = "") {
        val sanitizedUrl = LogSanitizer.sanitizeText(url)
        val metadata = mutableMapOf(
            "method" to method,
            "url" to sanitizedUrl,
            "timeout_ms" to timeoutMs.toString()
        )
        if (requestId.isNotEmpty()) {
            metadata["request_id"] = requestId
        }

        val entry = LogEntry(
            level = LogLevel.WARN,
            tag = TAG,
            category = LogCategory.API,
            message = "API Timeout: $method $sanitizedUrl after ${timeoutMs}ms",
            metadata = metadata
        )
        AppLogger.log(entry)
    }

    fun logRetry(method: String, url: String, attempt: Int, maxAttempts: Int, reason: String) {
        val sanitizedUrl = LogSanitizer.sanitizeText(url)
        val entry = LogEntry(
            level = LogLevel.WARN,
            tag = TAG,
            category = LogCategory.API,
            message = "API Retry: $method $sanitizedUrl attempt $attempt/$maxAttempts - $reason",
            metadata = mapOf(
                "method" to method,
                "url" to sanitizedUrl,
                "attempt" to attempt.toString(),
                "max_attempts" to maxAttempts.toString(),
                "reason" to reason
            )
        )
        AppLogger.log(entry)
    }
}

object ExceptionLogger {

    private const val TAG = "ExceptionLogger"

    fun logException(throwable: Throwable, context: String = "", metadata: Map<String, String> = emptyMap()) {
        val sanitizedMeta = metadata.mapValues { (key, value) ->
            LogSanitizer.sanitizeValue(key, value)
        }.toMutableMap()

        sanitizedMeta["exception_type"] = throwable::class.qualifiedName ?: "Unknown"
        sanitizedMeta["message"] = LogSanitizer.sanitizeText(throwable.message ?: "No message")
        sanitizedMeta["stack_trace"] = LogSanitizer.sanitizeStackTrace(throwable)

        if (context.isNotEmpty()) {
            sanitizedMeta["context"] = context
        }

        // Log cause chain
        var cause = throwable.cause
        var causeDepth = 1
        while (cause != null && causeDepth <= 5) {
            sanitizedMeta["cause_${causeDepth}_type"] = cause::class.qualifiedName ?: "Unknown"
            sanitizedMeta["cause_${causeDepth}_message"] = LogSanitizer.sanitizeText(cause.message ?: "No message")
            cause = cause.cause
            causeDepth++
        }

        val entry = LogEntry(
            level = LogLevel.ERROR,
            tag = TAG,
            category = LogCategory.EXCEPTION,
            message = "Exception${if (context.isNotEmpty()) " in $context" else ""}: ${throwable::class.simpleName} - ${LogSanitizer.sanitizeText(throwable.message ?: "")}",
            metadata = sanitizedMeta
        )
        AppLogger.log(entry)
    }

    fun logFatalException(throwable: Throwable, context: String = "") {
        val entry = LogEntry(
            level = LogLevel.ERROR,
            tag = TAG,
            category = LogCategory.EXCEPTION,
            message = "FATAL Exception${if (context.isNotEmpty()) " in $context" else ""}: ${throwable::class.simpleName}",
            metadata = mapOf(
                "fatal" to "true",
                "exception_type" to (throwable::class.qualifiedName ?: "Unknown"),
                "message" to LogSanitizer.sanitizeText(throwable.message ?: "No message"),
                "stack_trace" to LogSanitizer.sanitizeStackTrace(throwable)
            )
        )
        AppLogger.log(entry)
    }

    fun logWarning(message: String, context: String = "", metadata: Map<String, String> = emptyMap()) {
        val sanitizedMeta = metadata.mapValues { (key, value) ->
            LogSanitizer.sanitizeValue(key, value)
        }.toMutableMap()
        if (context.isNotEmpty()) {
            sanitizedMeta["context"] = context
        }

        val entry = LogEntry(
            level = LogLevel.WARN,
            tag = TAG,
            category = LogCategory.EXCEPTION,
            message = LogSanitizer.sanitizeText(message),
            metadata = sanitizedMeta
        )
        AppLogger.log(entry)
    }
}

// ============================================================
// 6. Central App Logger
// ============================================================

object AppLogger {

    private var fileLogger: FileLogger? = null
    private var isInitialized = false
    private var isDebugBuild = false

    fun initialize(application: Application, debug: Boolean = false) {
        if (isInitialized) return

        isDebugBuild = debug
        val logDir = File(application.filesDir, "logs")
        fileLogger = FileLogger(logDir)

        Timber.uprootAll()

        if (debug) {
            Timber.plant(DebugTree())
        }

        fileLogger?.let { Timber.plant(ProductionTree(it)) }

        // Set up uncaught exception handler
        val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler { thread, throwable ->
            ExceptionLogger.logFatalException(throwable, "UncaughtException on thread: ${thread.name}")
            defaultHandler?.uncaughtException(thread, throwable)
        }

        isInitialized = true

        Timber.i("AppLogger initialized (debug=$debug)")
    }

    fun log(entry: LogEntry) {
        val formattedMessage = entry.formatted()

        when (entry.level) {
            LogLevel.VERBOSE -> Timber.tag(entry.tag).v(formattedMessage)
            LogLevel.DEBUG -> Timber.tag(entry.tag).d(formattedMessage)
            LogLevel.INFO -> Timber.tag(entry.tag).i(formattedMessage)
            LogLevel.WARN -> Timber.tag(entry.tag).w(formattedMessage)
            LogLevel.ERROR -> Timber.tag(entry.tag).e(formattedMessage)
        }

        // Always write to file regardless of Timber filtering
        fileLogger?.write(entry)
    }

    fun getLogFiles(): List<File> {
        return fileLogger?.getLogFiles() ?: emptyList()
    }

    fun v(tag: String, message: String, metadata: Map<String, String> = emptyMap()) {
        log(LogEntry(level = LogLevel.VERBOSE, tag = tag, category = LogCategory.GENERAL, message = message, metadata = metadata))
    }

    fun d(tag: String, message: String, metadata: Map<String, String> = emptyMap()) {
        log(LogEntry(level = LogLevel.DEBUG, tag = tag, category = LogCategory.GENERAL, message = message, metadata = metadata))
    }

    fun i(tag: String, message: String, metadata: Map<String, String> = emptyMap()) {
        log(LogEntry(level = LogLevel.INFO, tag = tag, category = LogCategory.GENERAL, message = message, metadata = metadata))
    }

    fun w(tag: String, message: String, metadata: Map<String, String> = emptyMap()) {
        log(LogEntry(level = LogLevel.WARN, tag = tag, category = LogCategory.GENERAL, message = message, metadata = metadata))
    }

    fun e(tag: String, message: String, throwable: Throwable? = null, metadata: Map<String, String> = emptyMap()) {
        val meta = metadata.toMutableMap()
        if (throwable != null) {
            meta["stack_trace"] = LogSanitizer.sanitizeStackTrace(throwable)
        }
        log(LogEntry(level = LogLevel.ERROR, tag = tag, category = LogCategory.GENERAL, message = message, metadata = meta))
    }
}

