// ============================================================
// 8. Application class setup
// ============================================================

class LoggingApplication : Application() {

    override fun onCreate() {
        super.onCreate()

        // Initialize with debug flag based on build type
        val isDebug = true // Replace with BuildConfig.DEBUG in real app
        AppLogger.initialize(this, debug = isDebug)

        AppLogger.i("App", "Application created", mapOf("build_type" to if (isDebug) "debug" else "release"))
    }
}

// ============================================================
// 9. Usage Examples (demonstrating the full system)
// ============================================================

class UsageExamples {

    // --- Authentication Examples ---
    fun demonstrateAuthLogging() {
        // Login attempt
        AuthLogger.logLoginAttempt("user@example.com", "password")

        // Successful login
        AuthLogger.logLoginSuccess("user@example.com", "password", durationMs = 350)

        // Failed login
        AuthLogger.logLoginFailure("user@example.com", "invalid_credentials", "password")

        // Token refresh
        AuthLogger.logTokenRefresh(success = true)
        AuthLogger.logTokenRefresh(success = false, reason = "token_expired")

        // Logout
        AuthLogger.logLogout("user@example.com", "session_timeout")

        // Registration
        AuthLogger.logRegistrationAttempt("newuser@example.com")
        AuthLogger.logRegistrationSuccess("newuser@example.com")
        AuthLogger.logRegistrationFailure("newuser@example.com", "email_already_exists")
    }

    // --- Database Examples ---
    fun demonstrateDatabaseLogging() {
        // Query
        DatabaseLogger.logQuery(
            query = "SELECT * FROM users WHERE email = ? AND status = ?",
            parameters = mapOf("email" to "user@example.com", "status" to "active"),
            durationMs = 15,
            resultCount = 1
        )

        // Insert
        DatabaseLogger.logInsert(
            table = "users",
            values = mapOf("email" to "new@example.com", "name" to "John", "password" to "secret123"),
            durationMs = 8,
            rowId = 42
        )

        // Update
        DatabaseLogger.logUpdate(
            table = "users",
            values = mapOf("last_login" to "2024-01-15T10:30:00Z"),
            whereClause = "id = 42",
            durationMs = 5,
            rowsAffected = 1
        )

        // Delete
        DatabaseLogger.logDelete(
            table = "sessions",
            whereClause = "expired_at < datetime('now')",
            durationMs = 12,
            rowsAffected = 5
        )

        // Transaction
        DatabaseLogger.logTransaction("bulk_user_import", success = true, durationMs = 250)

        // Error
        try {
            throw RuntimeException("UNIQUE constraint failed: users.email")
        } catch (e: Exception) {
            DatabaseLogger.logError("insert_user", e)
        }

        // Migration
        DatabaseLogger.logMigration(fromVersion = 3, toVersion = 4, success = true, durationMs = 1200)
    }

    // --- API Examples ---
    fun demonstrateApiLogging() {
        // Request
        ApiLogger.logRequest(
            method = "POST",
            url = "https://api.example.com/v1/auth/login",
            headers = mapOf(
                "Content-Type" to "application/json",
                "Authorization" to "Bearer eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxMjM0NTY3ODkwIn0.abc123",
                "X-API-Key" to "sk_live_abc123def456"
            ),
            body = """{"email":"user@example.com","password":"mySecretPassword123"}""",
            requestId = "req_abc123"
        )

        // Response
        ApiLogger.logResponse(
            method = "POST",
            url = "https://api.example.com/v1/auth/login",
            statusCode = 200,
            headers = mapOf(
                "Content-Type" to "application/json",
                "Set-Cookie" to "session=abc123xyz"
            ),
            body = """{"token":"eyJhbGciOiJIUzI1NiJ9.eyJzdWIiOiIxMjM0NTY3ODkwIn0.abc123","user":{"email":"user@example.com"}}""",
            durationMs = 245,
            requestId = "req_abc123"
        )

        // Error response
        ApiLogger.logResponse(
            method = "GET",
            url = "https://api.example.com/v1/users/profile",
            statusCode = 401,
            body = """{"error":"unauthorized","message":"Token expired"}""",
            durationMs = 50
        )

        // Network error
        try {
            throw java.net.SocketTimeoutException("Connect timed out")
        } catch (e: Exception) {
            ApiLogger.logError(
                method = "GET",
                url = "https://api.example.com/v1/data",
                throwable = e,
                durationMs = 30000
            )
        }

        // Timeout
        ApiLogger.logTimeout("GET", "https://api.example.com/v1/slow-endpoint", 30000)

        // Retry
        ApiLogger.logRetry("POST", "https://api.example.com/v1/submit", attempt = 2, maxAttempts = 3, reason = "503 Service Unavailable")
    }

    // --- Exception Examples ---
    fun demonstrateExceptionLogging() {
        // General exception
        try {
            val list = listOf(1, 2, 3)
            @Suppress("UNUSED_VARIABLE")
            val item = list[5]
        } catch (e: Exception) {
            ExceptionLogger.logException(
                throwable = e,
                context = "UserProfileFragment.loadData",
                metadata = mapOf("user_id" to "12345")
            )
        }

        // Nested exception with cause
        try {
            try {
                throw java.sql.SQLException("Connection refused")
            } catch (e: Exception) {
                throw RuntimeException("Failed to load user data", e)
            }
        } catch (e: Exception) {
            ExceptionLogger.logException(e, "DataRepository.fetchUser")
        }

        // Warning
        ExceptionLogger.logWarning(
            "Memory usage above 80% threshold",
            context = "MemoryMonitor",
            metadata = mapOf("used_mb" to "256", "total_mb" to "320")
        )

        // General logging
        AppLogger.i("MainActivity", "Screen loaded", mapOf("screen" to "home", "load_time_ms" to "120"))
        AppLogger.w("CacheManager", "Cache miss for key: user_profile_123")
        AppLogger.e("PaymentService", "Payment processing failed", RuntimeException("Insufficient funds"))
    }
}